mapper.select:
select id, application_time applicationTime, first_review_time firstReviewTime, review_order_number reviewOrderNumber, review_operation reviewOperation, review_status reviewStatus, applicant, first_instance firstInstance, lock_status lockStatus, review_application_type reviewApplicationType, agent_account agentAccount, agent_type agentType, before_fixing beforeFixing, after_modification afterModification, locker, IF(locker = #{vo.adminName}, -1, 5) reviewOperation1, review_remark reviewRemark, application_information applicationInformation, creator, created_time createdTime, updater, updated_time updatedTime from agent_info_modify_review
AND application_time >= #{vo.applyStartTime}
AND application_time <= #{vo.applyEndTime}
AND first_review_time >= #{vo.firstFinishStartTime}
AND first_review_time <= #{vo.firstFinishEndTime}
AND agent_account = #{vo.agentAccount}
AND agent_type = #{vo.agentType}
AND review_operation = #{vo.reviewOperation}
AND review_status = #{vo.reviewStatus}
AND applicant = #{vo.applicant}
AND first_instance = #{vo.firstInstance}
AND lock_status = #{vo.lockStatus}
AND review_order_number = #{vo.agentReviewOrderNo}
ORDER BY applicationTime asc
ORDER BY applicationTime desc
ORDER BY firstReviewTime asc
ORDER BY firstReviewTime desc
ORDER BY reviewOperation1 ASC, review_operation ASC, review_status ASC, application_time ASC

select count(id) from agent_info_modify_review where site_code = #{siteCode} and review_application_type = #{code} and review_status in
#{reviewStatus}
and FIND_IN_SET(#{afterValue}, after_modification)>0
